package main

import (
	"fmt"
	"strings"

	"owldb/jsondata"
)

// PatchOperation represents a single PATCH operation
type PatchOperation struct {
	Op    string      `json:"op"`
	Path  string      `json:"path"`
	Value interface{} `json:"value"`
}

// ApplyPatches applies a list of patch operations to a document
func ApplyPatches(doc interface{}, patches []map[string]interface{}) (interface{}, bool, string) {
	// Convert document to JSONValue
	docValue, err := jsondata.NewJSONValue(doc)
	if err != nil {
		return doc, true, fmt.Sprintf("Failed to convert document: %v", err)
	}

	// Apply each patch in order
	for _, p := range patches {
		op, ok := p["op"].(string)
		if !ok {
			return doc, true, "Missing or invalid op field"
		}

		path, ok := p["path"].(string)
		if !ok {
			return doc, true, "Missing or invalid path field"
		}

		value, ok := p["value"]
		if !ok {
			return doc, true, "Missing value field"
		}

		// Apply the patch operation
		var newValue interface{}
		switch op {
		case "ArrayAdd":
			var updated bool
			newValue, updated, err = applyArrayAdd(docValue, path, value)
			if err != nil || !updated {
				return doc, true, fmt.Sprintf("ArrayAdd failed: %v", err)
			}

		case "ArrayRemove":
			var updated bool
			newValue, updated, err = applyArrayRemove(docValue, path, value)
			if err != nil || !updated {
				return doc, true, fmt.Sprintf("ArrayRemove failed: %v", err)
			}

		case "ObjectAdd":
			var updated bool
			newValue, updated, err = applyObjectAdd(docValue, path, value)
			if err != nil || !updated {
				return doc, true, fmt.Sprintf("ObjectAdd failed: %v", err)
			}

		default:
			return doc, true, fmt.Sprintf("Unknown operation: %s", op)
		}

		docValue, _ = jsondata.NewJSONValue(newValue)
	}

	// Return the modified document
	finalDoc, _ := unwrapJSONValue(docValue)
	return finalDoc, false, "patch applied"
}

// applyArrayAdd adds a value to an array
func applyArrayAdd(doc jsondata.JSONValue, path string, value interface{}) (interface{}, bool, error) {
	// Parse the path and navigate to the target
	target, modified, err := navigateAndModify(doc, path, func(target interface{}) (interface{}, bool, error) {
		arr, ok := target.([]interface{})
		if !ok {
			return target, false, fmt.Errorf("path does not refer to an array")
		}

		// Check if value already exists
		for _, item := range arr {
			if deepEqual(item, value) {
				return target, false, nil // Already exists, no change
			}
		}

		// Add the value
		newArr := append(arr, value)
		return newArr, true, nil
	})

	if err != nil {
		return nil, false, err
	}

	return target, modified, nil
}

// applyArrayRemove removes a value from an array
func applyArrayRemove(doc jsondata.JSONValue, path string, value interface{}) (interface{}, bool, error) {
	target, modified, err := navigateAndModify(doc, path, func(target interface{}) (interface{}, bool, error) {
		arr, ok := target.([]interface{})
		if !ok {
			return target, false, fmt.Errorf("path does not refer to an array")
		}

		// Find and remove the value
		newArr := make([]interface{}, 0)
		found := false
		for _, item := range arr {
			if !deepEqual(item, value) {
				newArr = append(newArr, item)
			} else {
				found = true
			}
		}

		if !found {
			return target, false, nil // Value not found, no change
		}

		return newArr, true, nil
	})

	if err != nil {
		return nil, false, err
	}

	return target, modified, nil
}

// applyObjectAdd adds a property to an object
func applyObjectAdd(doc jsondata.JSONValue, path string, value interface{}) (interface{}, bool, error) {
	target, modified, err := navigateAndModify(doc, path, func(target interface{}) (interface{}, bool, error) {
		obj, ok := target.(map[string]interface{})
		if !ok {
			return target, false, fmt.Errorf("path does not refer to an object property")
		}

		// Split the path to get the last key
		parts := strings.Split(strings.Trim(path, "/"), "/")
		if len(parts) == 0 {
			return target, false, fmt.Errorf("invalid path")
		}

		key := parts[len(parts)-1]

		// Check if property already exists
		if _, exists := obj[key]; exists {
			return target, false, nil // Property already exists
		}

		// Add the property
		obj[key] = value
		return obj, true, nil
	})

	if err != nil {
		return nil, false, err
	}

	return target, modified, nil
}

// navigateAndModify navigates to a path and applies a modification function
func navigateAndModify(doc jsondata.JSONValue, path string, modifyFunc func(interface{}) (interface{}, bool, error)) (interface{}, bool, error) {
	// For now, implement a simple version that works for single-level paths
	parts := strings.Split(strings.Trim(path, "/"), "/")

	// Unwrap the document
	docData, _ := unwrapJSONValue(doc)

	if len(parts) == 0 || parts[0] == "" {
		// Root modification
		return modifyFunc(docData)
	}

	// Navigate to the parent of the target
	current := docData
	for i := 0; i < len(parts)-1; i++ {
		if m, ok := current.(map[string]interface{}); ok {
			current = m[parts[i]]
		} else {
			return docData, false, fmt.Errorf("path does not exist")
		}
	}

	// Apply modification to the parent
	if m, ok := current.(map[string]interface{}); ok {
		key := parts[len(parts)-1]
		target := m[key]

		modified, isModified, err := modifyFunc(target)
		if err != nil {
			return docData, false, err
		}

		if isModified {
			m[key] = modified
		}

		return docData, isModified, nil
	}

	return docData, false, fmt.Errorf("path does not refer to an object")
}

// deepEqual checks if two values are deeply equal
func deepEqual(a, b interface{}) bool {
	// Simple implementation - can be enhanced
	switch av := a.(type) {
	case map[string]interface{}:
		bv, ok := b.(map[string]interface{})
		if !ok {
			return false
		}
		if len(av) != len(bv) {
			return false
		}
		for k, v := range av {
			if !deepEqual(v, bv[k]) {
				return false
			}
		}
		return true

	case []interface{}:
		bv, ok := b.([]interface{})
		if !ok {
			return false
		}
		if len(av) != len(bv) {
			return false
		}
		for i := range av {
			if !deepEqual(av[i], bv[i]) {
				return false
			}
		}
		return true

	case string, float64, bool, nil:
		return a == b

	default:
		return a == b
	}
}

// unwrapJSONValue unwraps a JSONValue to its underlying Go value
func unwrapJSONValue(jv jsondata.JSONValue) (interface{}, error) {
	// Use a simple visitor to get the underlying value
	visitor := &unwrapVisitor{}
	return jsondata.Accept(jv, visitor)
}

// unwrapVisitor is a visitor that unwraps a JSONValue
type unwrapVisitor struct{}

func (v *unwrapVisitor) Map(m map[string]jsondata.JSONValue) (interface{}, error) {
	result := make(map[string]interface{})
	for k, jv := range m {
		val, _ := unwrapJSONValue(jv)
		result[k] = val
	}
	return result, nil
}

func (v *unwrapVisitor) Slice(s []jsondata.JSONValue) (interface{}, error) {
	result := make([]interface{}, len(s))
	for i, jv := range s {
		val, _ := unwrapJSONValue(jv)
		result[i] = val
	}
	return result, nil
}

func (v *unwrapVisitor) Bool(b bool) (interface{}, error) {
	return b, nil
}

func (v *unwrapVisitor) Float64(f float64) (interface{}, error) {
	return f, nil
}

func (v *unwrapVisitor) String(s string) (interface{}, error) {
	return s, nil
}

func (v *unwrapVisitor) Null() (interface{}, error) {
	return nil, nil
}

package main

import (
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"strings"
)

// authHandler handles POST /auth
func authHandler(w http.ResponseWriter, r *http.Request, db *Database) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req map[string]string
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		respondJSON(w, http.StatusBadRequest, "Invalid request body")
		return
	}

	username, ok := req["username"]
	if !ok || username == "" {
		respondJSON(w, http.StatusBadRequest, "No username in request body")
		return
	}

	token, err := db.GenerateToken(username)
	if err != nil {
		respondJSON(w, http.StatusInternalServerError, fmt.Sprintf("Error generating token: %v", err))
		return
	}

	respondJSON(w, http.StatusOK, map[string]string{"token": token})
}

// logoutHandler handles DELETE /auth
func logoutHandler(w http.ResponseWriter, r *http.Request, db *Database) {
	if r.Method != http.MethodDelete {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	token := extractToken(r)
	if token == "" {
		respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	if !db.InvalidateToken(token) {
		respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

// v1Handler handles all /v1/* routes
func v1Handler(w http.ResponseWriter, r *http.Request, db *Database) {
	// Extract token and verify auth (except for /v1/ itself)
	path := r.URL.Path
	if path != "/v1" && path != "/v1/" {
		token := extractToken(r)
		if token == "" {
			respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
			return
		}
		if !db.ValidateToken(token) {
			respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
			return
		}
	}

	// Handle OPTIONS requests
	if r.Method == http.MethodOptions {
		w.Header().Set("Allow", "GET, PUT, DELETE, POST, PATCH, OPTIONS")
		w.Header().Set("Access-Control-Allow-Methods", "GET, PUT, DELETE, POST, PATCH, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.WriteHeader(http.StatusOK)
		return
	}

	// Handle /v1/ health check
	if path == "/v1" || path == "/v1/" {
		w.WriteHeader(http.StatusOK)
		return
	}

	// Parse the path
	pathParts := strings.Split(strings.TrimPrefix(path, "/v1/"), "/")
	if len(pathParts) == 0 {
		http.Error(w, "Bad request", http.StatusBadRequest)
		return
	}

	databaseName := pathParts[0]
	docPath := ""
	if len(pathParts) > 1 {
		docPath = strings.Join(pathParts[1:], "/")
	}

	// Route to appropriate handler
	if docPath == "" {
		// Database-level operations
		handleDatabase(w, r, db, databaseName)
	} else if strings.HasSuffix(path, "/") {
		// Collection operations
		handleCollection(w, r, db, databaseName, docPath)
	} else {
		// Document operations
		handleDocument(w, r, db, databaseName, docPath)
	}
}

// handleDatabase handles database-level operations (PUT, DELETE, GET)
func handleDatabase(w http.ResponseWriter, r *http.Request, db *Database, dbName string) {
	switch r.Method {
	case http.MethodPut:
		if err := db.CreateDatabase(dbName); err != nil {
			respondJSON(w, http.StatusBadRequest, err.Error())
			return
		}
		respondJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbName})
		w.Header().Set("Location", "/v1/"+dbName)

	case http.MethodDelete:
		if err := db.DeleteDatabase(dbName); err != nil {
			respondJSON(w, http.StatusBadRequest, err.Error())
			return
		}
		w.WriteHeader(http.StatusNoContent)

	case http.MethodGet:
		// GET on database - return it as a collection
		dbInst := db.GetDatabase(dbName)
		if dbInst == nil {
			respondJSON(w, http.StatusNotFound, "Database does not exist")
			return
		}
		// Return empty collection for now
		respondJSON(w, http.StatusOK, []interface{}{})

	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

// handleCollection handles collection operations (PUT, GET, DELETE)
func handleCollection(w http.ResponseWriter, r *http.Request, db *Database, dbName, collPath string) {
	dbInst := db.GetDatabase(dbName)
	if dbInst == nil {
		respondJSON(w, http.StatusBadRequest, "Database does not exist")
		return
	}

	switch r.Method {
	case http.MethodPut:
		// Create collection (mkdir)
		w.WriteHeader(http.StatusCreated)

	case http.MethodGet:
		// Check if this is a subscription request
		if r.Header.Get("Accept") == "text/event-stream" {
			interval := r.URL.Query().Get("interval")
			handleSubscribeCollectionHTTP(w, r, dbInst, collPath, interval)
		} else {
			// Get collection
			interval := r.URL.Query().Get("interval")
			handleCollectionQuery(w, r, dbInst, collPath, interval)
		}

	case http.MethodDelete:
		// Delete collection
		w.WriteHeader(http.StatusNoContent)

	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

// handleCollectionQuery handles collection queries with interval support
func handleCollectionQuery(w http.ResponseWriter, r *http.Request, db *DBInstance, collPath, interval string) {
	ctx := r.Context()

	// Parse interval if provided
	var startKey, endKey string
	startKey = ""              // Default: match all
	endKey = ""                // Default: match all

	if interval != "" {
		// Parse interval format: [low,high]
		interval = strings.TrimPrefix(interval, "[")
		interval = strings.TrimSuffix(interval, "]")
		parts := strings.Split(interval, ",")
		if len(parts) >= 1 {
			startKey = parts[0]
		}
		if len(parts) >= 2 {
			endKey = parts[1]
		}
	}

	// Prefix for collection filtering
	collPrefix := collPath
	if collPrefix != "" && !strings.HasSuffix(collPrefix, "/") {
		collPrefix += "/"
	}

	// Get all documents
	// For now, iterate through the skip list manually
	var docs []interface{}

	// Use a custom visitor to get all documents
	// Since we can't easily iterate the skip list, scan from the beginning
	if startKey == "" && endKey == "" {
		// No bounds specified - query from beginning to end
		// Use very large range to get all
		allStartKey := "\x00"
		allEndKey := "\uffff\uffff\uffff\uffff"

		results, err := db.index.Query(ctx, allStartKey, allEndKey)
		if err != nil {
			respondJSON(w, http.StatusInternalServerError, fmt.Sprintf("Query failed: %v", err))
			return
		}

		for _, pair := range results {
			docPath := pair.Key
			// Check if document is in the collection
			if collPrefix == "" {
				// Root collection - include all documents
				docs = append(docs, pair.Value.Value)
			} else if strings.HasPrefix(docPath, collPrefix) {
				// Check if it's a direct child (no "/" after prefix)
				remainder := strings.TrimPrefix(docPath, collPrefix)
				if !strings.Contains(remainder, "/") {
					docs = append(docs, pair.Value.Value)
				}
			}
		}
	} else {
		// Use specified interval
		if startKey == "" {
			startKey = "\x00"
		}
		if endKey == "" {
			endKey = "\uffff\uffff"
		}

		results, err := db.index.Query(ctx, startKey, endKey)
		if err != nil {
			respondJSON(w, http.StatusInternalServerError, fmt.Sprintf("Query failed: %v", err))
			return
		}

		for _, pair := range results {
			docPath := pair.Key
			if collPrefix == "" || (strings.HasPrefix(docPath, collPrefix) && !strings.Contains(strings.TrimPrefix(docPath, collPrefix), "/")) {
				docs = append(docs, pair.Value.Value)
			}
		}
	}

	if docs == nil {
		docs = []interface{}{}
	}

	respondJSON(w, http.StatusOK, docs)
}

// handleDocument handles document operations (GET, PUT, POST, DELETE, PATCH)
func handleDocument(w http.ResponseWriter, r *http.Request, db *Database, dbName, docPath string) {
	dbInst := db.GetDatabase(dbName)
	if dbInst == nil {
		respondJSON(w, http.StatusNotFound, "Database does not exist")
		return
	}

	switch r.Method {
	case http.MethodGet:
		// Check if this is a subscription request
		if r.Header.Get("Accept") == "text/event-stream" {
			handleSubscribeDocumentHTTP(w, r, dbInst, docPath)
		} else {
			handleGetDocument(w, dbInst, docPath)
		}

	case http.MethodPut:
		handlePutDocument(w, r, db, dbInst, docPath)

	case http.MethodPost:
		handlePostDocument(w, r, db, dbInst, docPath)

	case http.MethodDelete:
		handleDeleteDocument(w, dbInst, docPath)

	case http.MethodPatch:
		handlePatchDocument(w, r, dbInst, docPath)

	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

// handleGetDocument handles GET requests for documents
func handleGetDocument(w http.ResponseWriter, db *DBInstance, docPath string) {
	doc, found := db.index.Find(docPath)
	if !found {
		respondJSON(w, http.StatusNotFound, "Document not found")
		return
	}

	respondJSON(w, http.StatusOK, doc.Value)
}

// handlePutDocument handles PUT requests for documents
func handlePutDocument(w http.ResponseWriter, r *http.Request, db *Database, dbInst *DBInstance, docPath string) {
	mode := r.URL.Query().Get("mode")
	if mode == "" {
		mode = "overwrite"
	}

	body, err := io.ReadAll(r.Body)
	if err != nil {
		respondJSON(w, http.StatusBadRequest, "Failed to read body")
		return
	}

	var docValue interface{}
	if err := json.Unmarshal(body, &docValue); err != nil {
		respondJSON(w, http.StatusBadRequest, "Invalid JSON")
		return
	}

	// Validate document
	if err := db.ValidateDocument(docValue); err != nil {
		respondJSON(w, http.StatusBadRequest, fmt.Sprintf("Document validation failed: %v", err))
		return
	}

	// Check mode
	check := func(key string, currValue *Document, exists bool) (*Document, error) {
		if mode == "nooverwrite" && exists {
			return nil, fmt.Errorf("document already exists")
		}
		return &Document{
			Path:  docPath,
			Value: docValue,
		}, nil
	}

	_, err = dbInst.index.Upsert(docPath, check)
	if err != nil {
		respondJSON(w, http.StatusBadRequest, err.Error())
		return
	}

	// Notify subscribers
	dbInst.subscriptions.NotifyChange(docPath, "update", docValue)

	respondJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbInst.name + "/" + docPath})
}

// handlePostDocument handles POST requests for documents
func handlePostDocument(w http.ResponseWriter, r *http.Request, db *Database, dbInst *DBInstance, docPath string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		respondJSON(w, http.StatusBadRequest, "Failed to read body")
		return
	}

	var docValue interface{}
	if len(body) > 0 {
		if err := json.Unmarshal(body, &docValue); err != nil {
			respondJSON(w, http.StatusBadRequest, "Invalid JSON")
			return
		}
	}

	// Validate document
	if err := db.ValidateDocument(docValue); err != nil {
		respondJSON(w, http.StatusBadRequest, fmt.Sprintf("Document validation failed: %v", err))
		return
	}

	// POST always creates (overwrite)
	check := func(key string, currValue *Document, exists bool) (*Document, error) {
		return &Document{
			Path:  docPath,
			Value: docValue,
		}, nil
	}

	_, err = dbInst.index.Upsert(docPath, check)
	if err != nil {
		respondJSON(w, http.StatusBadRequest, err.Error())
		return
	}

	// Notify subscribers
	dbInst.subscriptions.NotifyChange(docPath, "update", docValue)

	respondJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbInst.name + "/" + docPath})
}

// handleDeleteDocument handles DELETE requests for documents
func handleDeleteDocument(w http.ResponseWriter, db *DBInstance, docPath string) {
	_, removed := db.index.Remove(docPath)
	if !removed {
		respondJSON(w, http.StatusNotFound, "Document not found")
		return
	}

	// Notify subscribers
	db.subscriptions.NotifyChange(docPath, "delete", nil)

	w.WriteHeader(http.StatusNoContent)
}

// handlePatchDocument handles PATCH requests for documents
func handlePatchDocument(w http.ResponseWriter, r *http.Request, db *DBInstance, docPath string) {
	// Get the document first
	doc, found := db.index.Find(docPath)
	if !found {
		respondJSON(w, http.StatusNotFound, "Document not found")
		return
	}

	var patches []map[string]interface{}
	if err := json.NewDecoder(r.Body).Decode(&patches); err != nil {
		respondJSON(w, http.StatusBadRequest, "Invalid patches")
		return
	}

	// Apply patches
	modified, failed, message := ApplyPatches(doc.Value, patches)

	// If patches succeeded, update the document
	if !failed {
		check := func(key string, currValue *Document, exists bool) (*Document, error) {
			return &Document{
				Path:  docPath,
				Value: modified,
			}, nil
		}

		db.index.Upsert(docPath, check)

		// Notify subscribers
		db.subscriptions.NotifyChange(docPath, "update", modified)
	}

	// Return response
	w.WriteHeader(http.StatusOK)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"uri":         "/v1/" + db.name + "/" + docPath,
		"patchFailed": failed,
		"message":     message,
	})
}

// handleSubscribeDocumentHTTP wraps the subscription handler for HTTP requests
func handleSubscribeDocumentHTTP(w http.ResponseWriter, r *http.Request, db *DBInstance, docPath string) {
	handleSubscribeDocument(w, r, db, docPath, db.subscriptions)
}

// handleSubscribeCollection wraps collection subscription for HTTP requests
func handleSubscribeCollectionHTTP(w http.ResponseWriter, r *http.Request, db *DBInstance, collPath, interval string) {
	handleSubscribeCollection(w, r, db, collPath, interval, db.subscriptions)
}

// extractToken extracts the bearer token from the Authorization header
func extractToken(r *http.Request) string {
	auth := r.Header.Get("Authorization")
	if auth == "" {
		return ""
	}

	const prefix = "Bearer "
	if !strings.HasPrefix(auth, prefix) {
		return ""
	}

	return auth[len(prefix):]
}

// respondJSON sends a JSON response
func respondJSON(w http.ResponseWriter, statusCode int, data interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)

	if data != nil {
		if err := json.NewEncoder(w).Encode(data); err != nil {
			slog.Error("Failed to encode response", "error", err)
		}
	}
}

package main

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"sync"
	"time"
)

// Subscription represents a client subscription to document changes
type Subscription struct {
	ID         string
	DocPath    string
	CollPath   string
	IsInterval bool
	StartKey   string
	EndKey     string
	Events     chan SubscriptionEvent
	Done       chan struct{}
}

// SubscriptionEvent represents a change event
type SubscriptionEvent struct {
	Type  string      // "create", "update", "delete"
	Path  string
	Value interface{}
}

// SubscriptionManager manages all active subscriptions
type SubscriptionManager struct {
	mu            sync.RWMutex
	subscriptions map[string]*Subscription
	docWatchers   map[string][]*Subscription // Map of doc path to subscriptions
}

// NewSubscriptionManager creates a new subscription manager
func NewSubscriptionManager() *SubscriptionManager {
	return &SubscriptionManager{
		subscriptions: make(map[string]*Subscription),
		docWatchers:   make(map[string][]*Subscription),
	}
}

// Subscribe creates a new subscription
func (sm *SubscriptionManager) Subscribe(docPath, collPath string, isInterval bool, startKey, endKey string) *Subscription {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	subID := fmt.Sprintf("sub_%d", time.Now().UnixNano())
	sub := &Subscription{
		ID:         subID,
		DocPath:    docPath,
		CollPath:   collPath,
		IsInterval: isInterval,
		StartKey:   startKey,
		EndKey:     endKey,
		Events:     make(chan SubscriptionEvent, 100),
		Done:       make(chan struct{}),
	}

	sm.subscriptions[subID] = sub

	// Register for document watching
	if docPath != "" {
		sm.docWatchers[docPath] = append(sm.docWatchers[docPath], sub)
	}

	return sub
}

// Unsubscribe removes a subscription
func (sm *SubscriptionManager) Unsubscribe(subID string) {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	sub, ok := sm.subscriptions[subID]
	if !ok {
		return
	}

	close(sub.Done)
	close(sub.Events)

	// Remove from watchers
	if sub.DocPath != "" {
		watchers := sm.docWatchers[sub.DocPath]
		for i, w := range watchers {
			if w.ID == subID {
				sm.docWatchers[sub.DocPath] = append(watchers[:i], watchers[i+1:]...)
				break
			}
		}
	}

	delete(sm.subscriptions, subID)
}

// NotifyChange notifies subscribers of a change
func (sm *SubscriptionManager) NotifyChange(docPath string, eventType string, value interface{}) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()

	// Notify document-specific subscribers
	if watchers, ok := sm.docWatchers[docPath]; ok {
		for _, sub := range watchers {
			select {
			case sub.Events <- SubscriptionEvent{Type: eventType, Path: docPath, Value: value}:
			case <-sub.Done:
			default:
				// Channel full, skip
			}
		}
	}

	// Notify collection subscribers
	for _, sub := range sm.subscriptions {
		if sub.DocPath == "" && matchesCollection(docPath, sub.CollPath, sub.StartKey, sub.EndKey) {
			select {
			case sub.Events <- SubscriptionEvent{Type: eventType, Path: docPath, Value: value}:
			case <-sub.Done:
			default:
				// Channel full, skip
			}
		}
	}
}

// matchesCollection checks if a document matches a collection subscription
func matchesCollection(docPath, collPath, startKey, endKey string) bool {
	collPrefix := collPath
	if collPrefix != "" && !strings.HasSuffix(collPrefix, "/") {
		collPrefix += "/"
	}

	// Check if document is in the collection
	if collPrefix != "" && !strings.HasPrefix(docPath, collPrefix) {
		return false
	}

	// Check interval bounds if specified
	if startKey != "" && docPath < startKey {
		return false
	}
	if endKey != "" && docPath > endKey {
		return false
	}

	return true
}

// HandleSubscribeRequest handles SSE subscription requests
func (db *DBInstance) HandleSubscribeRequest(w http.ResponseWriter, r *http.Request, docPath string, sm *SubscriptionManager) {
	// Check if it's a subscription request
	if r.Header.Get("Accept") != "text/event-stream" {
		// Try to get collection interval
		interval := r.URL.Query().Get("interval")
		if docPath == "" || strings.HasSuffix(r.RequestURI, "/") {
			// Collection subscription
			handleSubscribeCollection(w, r, db, docPath, interval, sm)
		} else {
			// Document subscription
			handleSubscribeDocument(w, r, db, docPath, sm)
		}
	}
}

// handleSubscribeDocument handles document subscription
func handleSubscribeDocument(w http.ResponseWriter, r *http.Request, db *DBInstance, docPath string, sm *SubscriptionManager) {
	// Get the current document
	doc, found := db.index.Find(docPath)

	// Create subscription
	sub := sm.Subscribe(docPath, "", false, "", "")

	// Set up SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")

	// Send initial event if document exists
	if found {
		sendSSEEvent(w, "update", docPath, doc.Value)
		w.(http.Flusher).Flush()
	} else {
		sendSSEEvent(w, "initial", docPath, nil)
		w.(http.Flusher).Flush()
	}

	// Listen for changes
	ticker := time.NewTicker(30 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case event := <-sub.Events:
			sendSSEEvent(w, event.Type, event.Path, event.Value)
			w.(http.Flusher).Flush()

		case <-ticker.C:
			// Keep-alive ping
			fmt.Fprintf(w, ": keepalive\n\n")
			w.(http.Flusher).Flush()

		case <-r.Context().Done():
			sm.Unsubscribe(sub.ID)
			return

		case <-sub.Done:
			return
		}
	}
}

// handleSubscribeCollection handles collection subscription
func handleSubscribeCollection(w http.ResponseWriter, r *http.Request, db *DBInstance, collPath, interval string, sm *SubscriptionManager) {
	// Parse interval if provided
	var startKey, endKey string
	startKey = "\x00"
	endKey = "\uffff\uffff"

	if interval != "" {
		interval = strings.TrimPrefix(interval, "[")
		interval = strings.TrimSuffix(interval, "]")
		parts := strings.Split(interval, ",")
		if len(parts) >= 1 && parts[0] != "" {
			startKey = parts[0]
		}
		if len(parts) >= 2 && parts[1] != "" {
			endKey = parts[1]
		}
	}

	// Create subscription
	sub := sm.Subscribe("", collPath, interval != "", startKey, endKey)

	// Set up SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")

	// Send initial collection state
	ctx := context.Background()
	results, err := db.index.Query(ctx, startKey, endKey)
	if err == nil {
		for _, pair := range results {
			docPath := pair.Key
			collPrefix := collPath
			if collPrefix != "" && !strings.HasSuffix(collPrefix, "/") {
				collPrefix += "/"
			}

			if collPrefix == "" || (strings.HasPrefix(docPath, collPrefix) && !strings.Contains(strings.TrimPrefix(docPath, collPrefix), "/")) {
				sendSSEEvent(w, "initial", docPath, pair.Value.Value)
			}
		}
	}
	w.(http.Flusher).Flush()

	// Listen for changes
	ticker := time.NewTicker(30 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case event := <-sub.Events:
			// Check if event matches subscription
			if matchesCollection(event.Path, collPath, startKey, endKey) {
				sendSSEEvent(w, event.Type, event.Path, event.Value)
				w.(http.Flusher).Flush()
			}

		case <-ticker.C:
			// Keep-alive ping
			fmt.Fprintf(w, ": keepalive\n\n")
			w.(http.Flusher).Flush()

		case <-r.Context().Done():
			sm.Unsubscribe(sub.ID)
			return

		case <-sub.Done:
			return
		}
	}
}

// sendSSEEvent sends a Server-Sent Event
func sendSSEEvent(w http.ResponseWriter, eventType string, path string, value interface{}) {
	fmt.Fprintf(w, "event: %s\n", eventType)

	// Create event data
	eventData := map[string]interface{}{
		"uri":   "/v1/" + path,
		"value": value,
	}

	data, _ := json.Marshal(eventData)
	fmt.Fprintf(w, "data: %s\n\n", string(data))
}

package main

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"os"
	"sync"
	"time"

	"github.com/santhosh-tekuri/jsonschema/v5"
)

// Database represents the main database instance
type Database struct {
	mu           sync.RWMutex
	databases    map[string]*DBInstance
	schemaPath   string
	schema       *jsonschema.Schema
	tokens       map[string]*TokenInfo
	tokenFile    string
}

// DBInstance represents a single database
type DBInstance struct {
	mu            sync.RWMutex
	name          string
	docs          map[string]DocumentNode
	index         *SkipList[string, *Document]
	subscriptions *SubscriptionManager
}

// Document represents a stored document
type Document struct {
	Path  string
	Value interface{}
	Mtime time.Time
}

// DocumentNode represents a node in the document tree
type DocumentNode struct {
	isCollection bool
	children     map[string]DocumentNode
	document     *Document
}

// TokenInfo holds token information
type TokenInfo struct {
	Username  string
	Token     string
	ExpiresAt time.Time
}

// NewDatabase creates a new database instance
func NewDatabase(schemaPath, tokenFile string) *Database {
	db := &Database{
		databases:  make(map[string]*DBInstance),
		schemaPath: schemaPath,
		tokens:     make(map[string]*TokenInfo),
		tokenFile:  tokenFile,
	}

	// Load schema
	if err := db.loadSchema(); err != nil {
		slog.Error("Failed to load schema", "error", err)
		os.Exit(1)
	}

	// Load tokens
	if tokenFile != "" {
		if err := db.loadTokens(); err != nil {
			slog.Error("Failed to load tokens", "error", err)
			os.Exit(1)
		}
	}

	return db
}

// loadSchema loads the JSON schema from file
func (db *Database) loadSchema() error {
	// Parse the schema by compiling the file path
	schema, err := jsonschema.Compile(db.schemaPath)
	if err != nil {
		return err
	}

	db.schema = schema
	return nil
}

// loadTokens loads tokens from the token file
func (db *Database) loadTokens() error {
	data, err := os.ReadFile(db.tokenFile)
	if err != nil {
		return err
	}

	var tokenMap map[string]string
	if err := json.Unmarshal(data, &tokenMap); err != nil {
		return err
	}

	// Convert to TokenInfo with 24-hour expiration
	for username, token := range tokenMap {
		db.tokens[token] = &TokenInfo{
			Username:  username,
			Token:     token,
			ExpiresAt: time.Now().Add(24 * time.Hour),
		}
	}

	return nil
}

// CreateDatabase creates a new database
func (db *Database) CreateDatabase(name string) error {
	db.mu.Lock()
	defer db.mu.Unlock()

	if _, exists := db.databases[name]; exists {
		return fmt.Errorf("database already exists")
	}

	db.databases[name] = &DBInstance{
		name:            name,
		docs:            make(map[string]DocumentNode),
		index:           NewSkipList[string, *Document](),
		subscriptions:   NewSubscriptionManager(),
	}

	return nil
}

// DeleteDatabase deletes a database
func (db *Database) DeleteDatabase(name string) error {
	db.mu.Lock()
	defer db.mu.Unlock()

	if _, exists := db.databases[name]; !exists {
		return fmt.Errorf("database does not exist")
	}

	delete(db.databases, name)
	return nil
}

// GetDatabase retrieves a database instance
func (db *Database) GetDatabase(name string) *DBInstance {
	db.mu.RLock()
	defer db.mu.RUnlock()
	return db.databases[name]
}

// ValidateToken validates a bearer token
func (db *Database) ValidateToken(token string) bool {
	db.mu.RLock()
	defer db.mu.RUnlock()

	info, exists := db.tokens[token]
	if !exists {
		return false
	}

	return time.Now().Before(info.ExpiresAt)
}

// GenerateToken creates a new token for a user
func (db *Database) GenerateToken(username string) (string, error) {
	db.mu.Lock()
	defer db.mu.Unlock()

	// For now, create a token based on username and timestamp
	token := fmt.Sprintf("%s_%d", username, time.Now().UnixNano())

	db.tokens[token] = &TokenInfo{
		Username:  username,
		Token:     token,
		ExpiresAt: time.Now().Add(24 * time.Hour),
	}

	return token, nil
}

// InvalidateToken invalidates a token
func (db *Database) InvalidateToken(token string) bool {
	db.mu.Lock()
	defer db.mu.Unlock()

	if _, exists := db.tokens[token]; !exists {
		return false
	}

	delete(db.tokens, token)
	return true
}

// ValidateDocument validates a document against the schema
func (db *Database) ValidateDocument(doc interface{}) error {
	if db.schema == nil {
		return nil
	}

	return db.schema.Validate(doc)
}

package main

import (
	"context"
	"cmp"
	"math/rand"
	"sync"
	"sync/atomic"
)

const (
	maxLevel = 16
)

// UpdateCheck is a function type for conditional updates
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair represents a key-value pair
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// SkipListNode represents a single node in the skip list
type SkipListNode[K cmp.Ordered, V any] struct {
	key      K
	value    V
	level    int
	forward  []*SkipListNode[K, V]
	mu       sync.Mutex
	marked   atomic.Bool
	fullyScan bool
}

// SkipList is a concurrent skip list with lazy synchronization
type SkipList[K cmp.Ordered, V any] struct {
	header  *SkipListNode[K, V]
	level   int
	mu      sync.RWMutex
	rng     *rand.Rand
}

// NewSkipList creates a new skip list
func NewSkipList[K cmp.Ordered, V any]() *SkipList[K, V] {
	header := &SkipListNode[K, V]{
		level:   maxLevel,
		forward: make([]*SkipListNode[K, V], maxLevel),
	}

	return &SkipList[K, V]{
		header: header,
		level:  0,
		rng:    rand.New(rand.NewSource(12345)),
	}
}

// randomLevel generates a random level for a new node
func (sl *SkipList[K, V]) randomLevel() int {
	level := 0
	for level < maxLevel && sl.rng.Float64() < 0.5 {
		level++
	}
	return level
}

// Find searches for a value by key
func (sl *SkipList[K, V]) Find(key K) (foundValue V, found bool) {
	sl.mu.RLock()
	defer sl.mu.RUnlock()

	pred := sl.header
	curr := sl.header

	for level := sl.level; level >= 0; level-- {
		for curr := pred.forward[level]; curr != nil; curr = curr.forward[level] {
			if curr.key < key {
				pred = curr
			} else {
				break
			}
		}
	}

	curr = pred.forward[0]
	if curr != nil && curr.key == key && !curr.marked.Load() {
		return curr.value, true
	}

	var zero V
	return zero, false
}

// Upsert updates or inserts a value with a check function
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error) {
	for {
		sl.mu.RLock()
		preds, succs, _ := sl.search(key)
		sl.mu.RUnlock()

		succ := succs[0]
		var currValue V
		var exists bool

		if succ != nil && succ.key == key {
			succ.mu.Lock()
			if !succ.marked.Load() {
				currValue = succ.value
				exists = true
				newValue, err := check(key, currValue, exists)
				if err != nil {
					succ.mu.Unlock()
					return false, err
				}
				succ.value = newValue
				succ.mu.Unlock()
				return true, nil
			}
			succ.mu.Unlock()
		} else {
			var zero V
			newValue, err := check(key, zero, false)
			if err != nil {
				return false, err
			}

			newNode := &SkipListNode[K, V]{
				key:     key,
				value:   newValue,
				level:   sl.randomLevel(),
				forward: make([]*SkipListNode[K, V], sl.randomLevel()+1),
			}

			sl.mu.Lock()
			preds, succs, _ = sl.search(key)

			if succs[0] != nil && succs[0].key == key {
				sl.mu.Unlock()
				continue
			}

			for i := 0; i <= newNode.level; i++ {
				newNode.forward[i] = succs[i]
				preds[i].forward[i] = newNode
			}

			if newNode.level > sl.level {
				sl.level = newNode.level
			}

			sl.mu.Unlock()
			return true, nil
		}
	}
}

// Remove removes a value by key
func (sl *SkipList[K, V]) Remove(key K) (removedValue V, removed bool) {
	for {
		sl.mu.RLock()
		preds, succs, _ := sl.search(key)
		sl.mu.RUnlock()

		succ := succs[0]
		if succ == nil || succ.key != key {
			var zero V
			return zero, false
		}

		succ.mu.Lock()
		if succ.marked.Load() {
			succ.mu.Unlock()
			continue
		}

		value := succ.value
		succ.marked.Store(true)

		sl.mu.Lock()
		preds, succs, _ = sl.search(key)

		for i := 0; i <= succ.level; i++ {
			if preds[i].forward[i] == succ {
				preds[i].forward[i] = succ.forward[i]
			}
		}

		sl.mu.Unlock()
		succ.mu.Unlock()

		return value, true
	}
}

// Query returns all elements with keys in the range [start, end]
func (sl *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
	sl.mu.RLock()
	defer sl.mu.RUnlock()

	var results []Pair[K, V]

	pred := sl.header
	for level := sl.level; level >= 1; level-- {
		for curr := pred.forward[level]; curr != nil; curr = curr.forward[level] {
			if curr.key < start {
				pred = curr
			} else {
				break
			}
		}
	}

	curr := pred.forward[0]
	for curr != nil {
		if curr.key > end {
			break
		}

		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}

		if !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.forward[0]
	}

	return results, nil
}

// search finds the predecessor and successor nodes for a given key
func (sl *SkipList[K, V]) search(key K) ([]*SkipListNode[K, V], []*SkipListNode[K, V], int) {
	preds := make([]*SkipListNode[K, V], maxLevel)
	succs := make([]*SkipListNode[K, V], maxLevel)

	pred := sl.header
	for level := sl.level; level >= 0; level-- {
		curr := pred.forward[level]
		for curr != nil && curr.key < key {
			pred = curr
			curr = curr.forward[level]
		}
		preds[level] = pred
		succs[level] = curr
	}

	return preds, succs, sl.level
}

// DBIndex interface for database indices
type DBIndex[K cmp.Ordered, V any] interface {
	Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error)
	Remove(key K) (removedValue V, removed bool)
	Find(key K) (foundValue V, found bool)
	Query(ctx context.Context, start K, end K) (results []Pair[K, V], err error)
}

// Verify that SkipList implements DBIndex
var _ DBIndex[string, any] = (*SkipList[string, any])(nil)

package main

import (
	"flag"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"strconv"
	"syscall"
)

func main() {
	var port int
	var schemaFile string
	var tokenFile string

	// Parse command-line flags
	flag.IntVar(&port, "p", 3318, "Port to listen on")
	flag.StringVar(&schemaFile, "s", "", "JSON schema file")
	flag.StringVar(&tokenFile, "t", "", "Token file")
	flag.Parse()

	// Validate required arguments
	if schemaFile == "" {
		slog.Error("Schema file required", "error", "-s flag is required")
		os.Exit(1)
	}

	// Initialize the database server
	db := NewDatabase(schemaFile, tokenFile)

	// Create HTTP server
	mux := http.NewServeMux()
	setupRoutes(mux, db)

	server := http.Server{
		Addr:    ":" + strconv.Itoa(port),
		Handler: mux,
	}

	// signal.Notify requires the channel to be buffered
	ctrlc := make(chan os.Signal, 1)
	signal.Notify(ctrlc, os.Interrupt, syscall.SIGTERM)
	go func() {
		// Wait for Ctrl-C signal
		<-ctrlc
		server.Close()
	}()

	// Start server
	slog.Info("Listening", "port", port)
	err := server.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		slog.Error("Server closed", "error", err)
	} else {
		slog.Info("Server closed", "error", err)
	}
}

func setupRoutes(mux *http.ServeMux, db *Database) {
	// Auth routes
	mux.HandleFunc("POST /auth", func(w http.ResponseWriter, r *http.Request) {
		authHandler(w, r, db)
	})
	mux.HandleFunc("DELETE /auth", func(w http.ResponseWriter, r *http.Request) {
		logoutHandler(w, r, db)
	})

	// Catch-all for /v1/ routes
	mux.HandleFunc("/v1/", func(w http.ResponseWriter, r *http.Request) {
		v1Handler(w, r, db)
	})
}

