+package main
+
+import (
+	"context"
+	"encoding/json"
+	"fmt"
+	"net/http"
+	"strings"
+	"sync"
+	"time"
+)
+
+// Subscription represents a client subscription to document changes
+type Subscription struct {
+	ID         string
+	DocPath    string
+	CollPath   string
+	IsInterval bool
+	StartKey   string
+	EndKey     string
+	Events     chan SubscriptionEvent
+	Done       chan struct{}
+}
+
+// SubscriptionEvent represents a change event
+type SubscriptionEvent struct {
+	Type  string      // "create", "update", "delete"
+	Path  string
+	Value interface{}
+}
+
+// SubscriptionManager manages all active subscriptions
+type SubscriptionManager struct {
+	mu            sync.RWMutex
+	subscriptions map[string]*Subscription
+	docWatchers   map[string][]*Subscription // Map of doc path to subscriptions
+}
+
+// NewSubscriptionManager creates a new subscription manager
+func NewSubscriptionManager() *SubscriptionManager {
+	return &SubscriptionManager{
+		subscriptions: make(map[string]*Subscription),
+		docWatchers:   make(map[string][]*Subscription),
+	}
+}
+
+// Subscribe creates a new subscription
+func (sm *SubscriptionManager) Subscribe(docPath, collPath string, isInterval bool, startKey, endKey string) *Subscription {
+	sm.mu.Lock()
+	defer sm.mu.Unlock()
+
+	subID := fmt.Sprintf("sub_%d", time.Now().UnixNano())
+	sub := &Subscription{
+		ID:         subID,
+		DocPath:    docPath,
+		CollPath:   collPath,
+		IsInterval: isInterval,
+		StartKey:   startKey,
+		EndKey:     endKey,
+		Events:     make(chan SubscriptionEvent, 100),
+		Done:       make(chan struct{}),
+	}
+
+	sm.subscriptions[subID] = sub
+
+	// Register for document watching
+	if docPath != "" {
+		sm.docWatchers[docPath] = append(sm.docWatchers[docPath], sub)
+	}
+
+	return sub
+}
+
+// Unsubscribe removes a subscription
+func (sm *SubscriptionManager) Unsubscribe(subID string) {
+	sm.mu.Lock()
+	defer sm.mu.Unlock()
+
+	sub, ok := sm.subscriptions[subID]
+	if !ok {
+		return
+	}
+
+	close(sub.Done)
+	close(sub.Events)
+
+	// Remove from watchers
+	if sub.DocPath != "" {
+		watchers := sm.docWatchers[sub.DocPath]
+		for i, w := range watchers {
+			if w.ID == subID {
+				sm.docWatchers[sub.DocPath] = append(watchers[:i], watchers[i+1:]...)
+				break
+			}
+		}
+	}
+
+	delete(sm.subscriptions, subID)
+}
+
+// NotifyChange notifies subscribers of a change
+func (sm *SubscriptionManager) NotifyChange(docPath string, eventType string, value interface{}) {
+	sm.mu.RLock()
+	defer sm.mu.RUnlock()
+
+	// Notify document-specific subscribers
+	if watchers, ok := sm.docWatchers[docPath]; ok {
+		for _, sub := range watchers {
+			select {
+			case sub.Events <- SubscriptionEvent{Type: eventType, Path: docPath, Value: value}:
+			case <-sub.Done:
+			default:
+				// Channel full, skip
+			}
+		}
+	}
+
+	// Notify collection subscribers
+	for _, sub := range sm.subscriptions {
+		if sub.DocPath == "" && matchesCollection(docPath, sub.CollPath, sub.StartKey, sub.EndKey) {
+			select {
+			case sub.Events <- SubscriptionEvent{Type: eventType, Path: docPath, Value: value}:
+			case <-sub.Done:
+			default:
+				// Channel full, skip
+			}
+		}
+	}
+}
+
+// matchesCollection checks if a document matches a collection subscription
+func matchesCollection(docPath, collPath, startKey, endKey string) bool {
+	collPrefix := collPath
+	if collPrefix != "" && !strings.HasSuffix(collPrefix, "/") {
+		collPrefix += "/"
+	}
+
+	// Check if document is in the collection
+	if collPrefix != "" && !strings.HasPrefix(docPath, collPrefix) {
+		return false
+	}
+
+	// Check interval bounds if specified
+	if startKey != "" && docPath < startKey {
+		return false
+	}
+	if endKey != "" && docPath > endKey {
+		return false
+	}
+
+	return true
+}
+
+// HandleSubscribeRequest handles SSE subscription requests
+func (db *DBInstance) HandleSubscribeRequest(w http.ResponseWriter, r *http.Request, docPath string, sm *SubscriptionManager) {
+	// Check if it's a subscription request
+	if r.Header.Get("Accept") != "text/event-stream" {
+		// Try to get collection interval
+		interval := r.URL.Query().Get("interval")
+		if docPath == "" || strings.HasSuffix(r.RequestURI, "/") {
+			// Collection subscription
+			handleSubscribeCollection(w, r, db, docPath, interval, sm)
+		} else {
+			// Document subscription
+			handleSubscribeDocument(w, r, db, docPath, sm)
+		}
+	}
+}
+
+// handleSubscribeDocument handles document subscription
+func handleSubscribeDocument(w http.ResponseWriter, r *http.Request, db *DBInstance, docPath string, sm *SubscriptionManager) {
+	// Get the current document
+	doc, found := db.index.Find(docPath)
+
+	// Create subscription
+	sub := sm.Subscribe(docPath, "", false, "", "")
+
+	// Set up SSE headers
+	w.Header().Set("Content-Type", "text/event-stream")
+	w.Header().Set("Cache-Control", "no-cache")
+	w.Header().Set("Connection", "keep-alive")
+	w.Header().Set("Access-Control-Allow-Origin", "*")
+
+	// Send initial event if document exists
+	if found {
+		sendSSEEvent(w, "update", docPath, doc.Value)
+		w.(http.Flusher).Flush()
+	} else {
+		sendSSEEvent(w, "initial", docPath, nil)
+		w.(http.Flusher).Flush()
+	}
+
+	// Listen for changes
+	ticker := time.NewTicker(30 * time.Second)
+	defer ticker.Stop()
+
+	for {
+		select {
+		case event := <-sub.Events:
+			sendSSEEvent(w, event.Type, event.Path, event.Value)
+			w.(http.Flusher).Flush()
+
+		case <-ticker.C:
+			// Keep-alive ping
+			fmt.Fprintf(w, ": keepalive\n\n")
+			w.(http.Flusher).Flush()
+
+		case <-r.Context().Done():
+			sm.Unsubscribe(sub.ID)
+			return
+
+		case <-sub.Done:
+			return
+		}
+	}
+}
+
+// handleSubscribeCollection handles collection subscription
+func handleSubscribeCollection(w http.ResponseWriter, r *http.Request, db *DBInstance, collPath, interval string, sm *SubscriptionManager) {
+	// Parse interval if provided
+	var startKey, endKey string
+	startKey = "\x00"
+	endKey = "\uffff\uffff"
+
+	if interval != "" {
+		interval = strings.TrimPrefix(interval, "[")
+		interval = strings.TrimSuffix(interval, "]")
+		parts := strings.Split(interval, ",")
+		if len(parts) >= 1 && parts[0] != "" {
+			startKey = parts[0]
+		}
+		if len(parts) >= 2 && parts[1] != "" {
+			endKey = parts[1]
+		}
+	}
+
+	// Create subscription
+	sub := sm.Subscribe("", collPath, interval != "", startKey, endKey)
+
+	// Set up SSE headers
+	w.Header().Set("Content-Type", "text/event-stream")
+	w.Header().Set("Cache-Control", "no-cache")
+	w.Header().Set("Connection", "keep-alive")
+	w.Header().Set("Access-Control-Allow-Origin", "*")
+
+	// Send initial collection state
+	ctx := context.Background()
+	results, err := db.index.Query(ctx, startKey, endKey)
+	if err == nil {
+		for _, pair := range results {
+			docPath := pair.Key
+			collPrefix := collPath
+			if collPrefix != "" && !strings.HasSuffix(collPrefix, "/") {
+				collPrefix += "/"
+			}
+
+			if collPrefix == "" || (strings.HasPrefix(docPath, collPrefix) && !strings.Contains(strings.TrimPrefix(docPath, collPrefix), "/")) {
+				sendSSEEvent(w, "initial", docPath, pair.Value.Value)
+			}
+		}
+	}
+	w.(http.Flusher).Flush()
+
+	// Listen for changes
+	ticker := time.NewTicker(30 * time.Second)
+	defer ticker.Stop()
+
+	for {
+		select {
+		case event := <-sub.Events:
+			// Check if event matches subscription
+			if matchesCollection(event.Path, collPath, startKey, endKey) {
+				sendSSEEvent(w, event.Type, event.Path, event.Value)
+				w.(http.Flusher).Flush()
+			}
+
+		case <-ticker.C:
+			// Keep-alive ping
+			fmt.Fprintf(w, ": keepalive\n\n")
+			w.(http.Flusher).Flush()
+
+		case <-r.Context().Done():
+			sm.Unsubscribe(sub.ID)
+			return
+
+		case <-sub.Done:
+			return
+		}
+	}
+}
+
+// sendSSEEvent sends a Server-Sent Event
+func sendSSEEvent(w http.ResponseWriter, eventType string, path string, value interface{}) {
+	fmt.Fprintf(w, "event: %s\n", eventType)
+
+	// Create event data
+	eventData := map[string]interface{}{
+		"uri":   "/v1/" + path,
+		"value": value,
+	}
+
+	data, _ := json.Marshal(eventData)
+	fmt.Fprintf(w, "data: %s\n\n", string(data))
+}
